  "inlineSchema": "// prisma/schema.prisma\n// EcoTrack Database Schema\n// Database: PostgreSQL\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider  = \"postgresql\"\n  url       = env(\"DATABASE_URL\")\n  directUrl = env(\"DIRECT_URL\")\n}\n\n// ─────────────────────────────────────────────\n// USER MODEL\n// ─────────────────────────────────────────────\nmodel User {\n  id           String   @id @default(cuid())\n  firstName    String\n  lastName     String\n  email        String   @unique\n  passwordHash String\n  role         Role     @default(USER)\n  isActive     Boolean  @default(true)\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  // Relations\n  company         Company?\n  emissionEntries EmissionEntry[]\n  refreshTokens   RefreshToken[]\n\n  @@map(\"users\")\n}\n\nenum Role {\n  USER\n  ADMIN\n}\n\n// ─────────────────────────────────────────────\n// REFRESH TOKEN MODEL\n// ─────────────────────────────────────────────\nmodel RefreshToken {\n  id        String   @id @default(cuid())\n  token     String   @unique\n  userId    String\n  expiresAt DateTime\n  createdAt DateTime @default(now())\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@map(\"refresh_tokens\")\n}\n\n// ─────────────────────────────────────────────\n// COMPANY MODEL\n// ─────────────────────────────────────────────\nmodel Company {\n  id                  String       @id @default(cuid())\n  userId              String       @unique\n  businessName        String\n  industryType        IndustryType @default(OTHER)\n  location            String?\n  country             String       @default(\"kenya\")\n  numberOfEmployees   Int          @default(1)\n  registrationNumber  String?\n  contactEmail        String?\n  contactPhone        String?\n  businessDescription String?\n  yearEstablished     String?\n  createdAt           DateTime     @default(now())\n  updatedAt           DateTime     @updatedAt\n\n  // Relations\n  user            User            @relation(fields: [userId], references: [id], onDelete: Cascade)\n  emissionEntries EmissionEntry[]\n\n  @@map(\"companies\")\n}\n\nenum IndustryType {\n  RETAIL\n  MANUFACTURING\n  TECHNOLOGY\n  HEALTHCARE\n  EDUCATION\n  HOSPITALITY\n  TRANSPORTATION\n  CONSTRUCTION\n  AGRICULTURE\n  ENERGY\n  FINANCIAL_SERVICES\n  CONSULTING\n  REAL_ESTATE\n  MEDIA\n  OTHER\n}\n\n// ─────────────────────────────────────────────\n// EMISSION ENTRY MODEL\n// Core data table: stores each monthly submission\n// ─────────────────────────────────────────────\nmodel EmissionEntry {\n  id        String   @id @default(cuid())\n  userId    String\n  companyId String?\n  month     Int // 1-12\n  year      Int\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Scope 1 - Direct Emissions\n  fuelType     FuelType?\n  fuelQuantity Float? // litres or kg depending on fuel type\n\n  // Scope 2 - Purchased Electricity\n  electricityKwh Float? // kWh\n\n  // Scope 3 - Indirect\n  wasteKg   Float? // kg of waste\n  wasteType WasteType @default(LANDFILL)\n  flightKm  Float? // business travel km\n\n  // Calculated totals (stored for performance)\n  scope1Emissions Float @default(0) // kg CO2e\n  scope2Emissions Float @default(0) // kg CO2e\n  scope3Emissions Float @default(0) // kg CO2e\n  totalEmissions  Float @default(0) // kg CO2e\n\n  // Notes\n  notes String?\n\n  // Relations\n  user    User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  company Company? @relation(fields: [companyId], references: [id], onDelete: SetNull)\n\n  @@unique([userId, month, year]) // One entry per user per month\n  @@map(\"emission_entries\")\n}\n\nenum FuelType {\n  PETROL\n  DIESEL\n  KEROSENE\n  LNG\n  CNG\n  LPG\n  WOOD\n  COAL\n}\n\nenum WasteType {\n  LANDFILL\n  RECYCLED\n  COMPOSTED\n  INCINERATED\n  HAZARDOUS\n}\n",
